// AgentManagerServiceServer is the server API for AgentManagerService service.
// All implementations must embed UnimplementedAgentManagerServiceServer
// for forward compatibility.
//
// AgentManagerService is the stable v1 inter-service contract for the agent
// orchestration domain. It owns flows, stages, roles, prompt templates, agent
// sessions, agent runs, acceptance state, follow-up intents and human gate refs.
type AgentManagerServiceServer interface {
	// CreateFlow creates a flow in the requested scope.
	CreateFlow(context.Context, *CreateFlowRequest) (*FlowResponse, error)
	// UpdateFlow changes safe flow metadata without mutating immutable versions.
	UpdateFlow(context.Context, *UpdateFlowRequest) (*FlowResponse, error)
	// CreateFlowVersion creates an immutable flow definition version.
	CreateFlowVersion(context.Context, *CreateFlowVersionRequest) (*FlowVersionResponse, error)
	// ActivateFlowVersion activates one version for future sessions and runs.
	ActivateFlowVersion(context.Context, *ActivateFlowVersionRequest) (*FlowVersionResponse, error)
	// GetFlow returns authoritative flow state.
	GetFlow(context.Context, *GetFlowRequest) (*FlowResponse, error)
	// ListFlows returns flows by scope and status.
	ListFlows(context.Context, *ListFlowsRequest) (*ListFlowsResponse, error)
	// CreateRoleProfile creates an agent role profile.
	CreateRoleProfile(context.Context, *CreateRoleProfileRequest) (*RoleProfileResponse, error)
	// UpdateRoleProfile changes safe role metadata and policy refs.
	UpdateRoleProfile(context.Context, *UpdateRoleProfileRequest) (*RoleProfileResponse, error)
	// GetRoleProfile returns authoritative role state.
	GetRoleProfile(context.Context, *GetRoleProfileRequest) (*RoleProfileResponse, error)
	// ListRoleProfiles returns role profiles by scope, kind and status.
	ListRoleProfiles(context.Context, *ListRoleProfilesRequest) (*ListRoleProfilesResponse, error)
	// GetPromptTemplate returns prompt template metadata without template body.
	GetPromptTemplate(context.Context, *GetPromptTemplateRequest) (*PromptTemplateResponse, error)
	// ListPromptTemplates returns prompt templates by role and kind.
	ListPromptTemplates(context.Context, *ListPromptTemplatesRequest) (*ListPromptTemplatesResponse, error)
	// CreatePromptTemplateVersion creates a prompt template version for a role.
	CreatePromptTemplateVersion(context.Context, *CreatePromptTemplateVersionRequest) (*PromptTemplateVersionResponse, error)
	// ActivatePromptTemplateVersion activates one prompt version for future runs.
	ActivatePromptTemplateVersion(context.Context, *ActivatePromptTemplateVersionRequest) (*PromptTemplateVersionResponse, error)
	// GetPromptTemplateVersion returns one prompt template version.
	GetPromptTemplateVersion(context.Context, *GetPromptTemplateVersionRequest) (*PromptTemplateVersionResponse, error)
	// ListPromptTemplateVersions returns prompt versions by role and kind.
	ListPromptTemplateVersions(context.Context, *ListPromptTemplateVersionsRequest) (*ListPromptTemplateVersionsResponse, error)
	// StartAgentSession creates or continues an agent session.
	StartAgentSession(context.Context, *StartAgentSessionRequest) (*AgentSessionResponse, error)
	// StartAgentRun creates a role run and records immutable context refs.
	StartAgentRun(context.Context, *StartAgentRunRequest) (*AgentRunResponse, error)
	// RecordRunState records a generic run lifecycle transition from runtime, MCP or hook ingress.
	RecordRunState(context.Context, *RecordRunStateRequest) (*AgentRunResponse, error)
	// ReportAgentRunState records a bounded state report from an agent-runner bound to one runtime job.
	ReportAgentRunState(context.Context, *ReportAgentRunStateRequest) (*AgentRunResponse, error)
	// GetAgentRunRuntimeStatus возвращает безопасное состояние runtime для одного run.
	GetAgentRunRuntimeStatus(context.Context, *GetAgentRunRuntimeStatusRequest) (*AgentRunRuntimeStatusResponse, error)
	// RecordSessionStateSnapshot records metadata for a Codex session state object.
	RecordSessionStateSnapshot(context.Context, *RecordSessionStateSnapshotRequest) (*AgentSessionStateSnapshotResponse, error)
	// RequestAcceptance requests acceptance checks for a session, run and stage.
	RequestAcceptance(context.Context, *RequestAcceptanceRequest) (*AcceptanceResultResponse, error)
	// RecordAcceptanceResult records acceptance state after machine or role checks.
	RecordAcceptanceResult(context.Context, *RecordAcceptanceResultRequest) (*AcceptanceResultResponse, error)
	// GetAcceptanceResult returns one acceptance result.
	GetAcceptanceResult(context.Context, *GetAcceptanceResultRequest) (*AcceptanceResultResponse, error)
	// ListAcceptanceResults returns acceptance results by session, run, stage or status.
	ListAcceptanceResults(context.Context, *ListAcceptanceResultsRequest) (*ListAcceptanceResultsResponse, error)
	// CreateFollowUpIntent records an intent for the next provider-native work item.
	CreateFollowUpIntent(context.Context, *CreateFollowUpIntentRequest) (*FollowUpIntentResponse, error)
	// DispatchFollowUpIntent sends a requested follow-up intent to provider-hub as a typed provider command.
	DispatchFollowUpIntent(context.Context, *DispatchFollowUpIntentRequest) (*FollowUpIntentResponse, error)
	// RecordAgentActivity records one safe timeline entry for a session or run.
	RecordAgentActivity(context.Context, *RecordAgentActivityRequest) (*AgentActivityResponse, error)
	// ListAgentActivities returns safe timeline entries by session or run.
	ListAgentActivities(context.Context, *ListAgentActivitiesRequest) (*ListAgentActivitiesResponse, error)
	// RequestHumanGate records an owner-decision wait and safe interaction/governance refs.
	RequestHumanGate(context.Context, *RequestHumanGateRequest) (*HumanGateRequestResponse, error)
	// RecordHumanGateDecision records a normalized owner decision outcome.
	RecordHumanGateDecision(context.Context, *RecordHumanGateDecisionRequest) (*HumanGateRequestResponse, error)
	// GetHumanGateRequest returns one owner-decision wait.
	GetHumanGateRequest(context.Context, *GetHumanGateRequestRequest) (*HumanGateRequestResponse, error)
	// ListHumanGateRequests returns owner-decision waits by session, run, stage or state.
	ListHumanGateRequests(context.Context, *ListHumanGateRequestsRequest) (*ListHumanGateRequestsResponse, error)
	// GetAgentSession returns authoritative session state.
	GetAgentSession(context.Context, *GetAgentSessionRequest) (*AgentSessionResponse, error)
	// ListAgentRuns returns agent runs by session, role, status or provider target.
	ListAgentRuns(context.Context, *ListAgentRunsRequest) (*ListAgentRunsResponse, error)
	mustEmbedUnimplementedAgentManagerServiceServer()
}

